import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Heart, ShoppingCart, CheckCircle2, Clock } from 'lucide-react';

// Perfectly mapped imports based on your folder structure!
import { useCart } from '../../hooks/useCart';
// import { useWishlist } from '../../hooks/useWishlist'; // Uncomment if you use a wishlist hook

const ProductCard = ({ product }) => {
  const { addItem } = useCart();
  // const { toggleItem } = useWishlist(); 

  // Fallback data to match your screenshots if API data is missing
  const {
    _id = '1',
    name = 'Premium Leather Sofa',
    finish = 'Premium Walnut Finish',
    price = 45999,
    mrp = 65000,
    image = 'https://via.placeholder.com/400x300',
    stockStatus = 'in_stock', // 'in_stock' or 'low_stock'
    stockLeft = 5
  } = product || {};

  const [isWishlisted, setIsWishlisted] = useState(false);

  // Calculate discount
  const discountPercent = mrp > price ? Math.round(((mrp - price) / mrp) * 100) : 0;

  const handleWishlistClick = (e) => {
    e.preventDefault(); // Prevents navigating to product page when clicking the heart
    e.stopPropagation();
    setIsWishlisted(!isWishlisted);

    // Wire this up to your actual state management
    // toggleItem(product);
  };

  const handleAddToCart = (e) => {
    e.preventDefault(); // Prevents navigating to product page when clicking add to cart
    e.stopPropagation();

    // Wiring up your actual cart hook
    if (addItem) {
      addItem({ ...product, quantity: 1 });
    }
  };

  return (
    <div className="bg-white rounded-2xl border border-gray-100 shadow-sm hover:shadow-lg transition-all duration-300 overflow-hidden flex flex-col group">

      {/* IMAGE SECTION */}
      <div className="relative aspect-[4/3] bg-gray-100 overflow-hidden cursor-pointer">
        <Link to={`/product/${_id}`}>
          <img
            src={image}
            alt={name}
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700 ease-out"
          />
        </Link>

        {/* Discount Badge */}
        {discountPercent > 0 && (
          <div className="absolute top-3 left-3 bg-[#dc2626] text-white text-xs font-bold px-2.5 py-1 rounded shadow-sm tracking-wide">
            {discountPercent}% OFF
          </div>
        )}

        {/* PREMIUM WISHLIST BUTTON (Glassmorphism Effect) */}
        <button
          onClick={handleWishlistClick}
          className="absolute top-3 right-3 w-9 h-9 flex items-center justify-center rounded-full bg-black/30 backdrop-blur-md hover:bg-black/50 transition-all duration-300 outline-none focus:outline-none focus:ring-0 active:scale-90 z-10"
        >
          <Heart
            size={18}
            className={`transition-all duration-300 ${isWishlisted
                ? 'fill-white text-white scale-110'
                : 'text-white stroke-[2px] group-hover:scale-110'
              }`}
          />
        </button>
      </div>

      {/* CONTENT SECTION */}
      <div className="p-5 flex flex-col flex-grow">
        <Link to={`/product/${_id}`} className="block">
          <h3 className="text-[17px] font-bold text-gray-900 group-hover:text-[#f97316] transition-colors duration-200 truncate tracking-tight">
            {name}
          </h3>
        </Link>

        <p className="text-sm text-gray-500 mt-1 mb-4">
          {finish}
        </p>

        {/* Pricing */}
        <div className="flex items-baseline gap-2 mb-3">
          <span className="text-xl font-bold text-gray-900 tracking-tight">
            ₹{price.toLocaleString('en-IN')}
          </span>
          {mrp > price && (
            <span className="text-sm font-medium text-gray-400 line-through">
              ₹{mrp.toLocaleString('en-IN')}
            </span>
          )}
        </div>

        {/* Stock Status */}
        <div className="mb-5 mt-auto">
          {stockStatus === 'in_stock' ? (
            <div className="flex items-center gap-1.5 text-sm font-medium text-[#16a34a]">
              <CheckCircle2 size={16} />
              In Stock
            </div>
          ) : (
            <div className="flex items-center gap-1.5 text-sm font-medium text-[#ea580c]">
              <Clock size={16} />
              Only {stockLeft} left
            </div>
          )}
        </div>

        {/* Add to Cart Button */}
        <button
          onClick={handleAddToCart}
          className="w-full bg-[#f97316] text-white py-3 rounded-xl font-bold tracking-wide flex items-center justify-center gap-2 hover:bg-[#ea580c] hover:shadow-lg hover:shadow-orange-500/20 active:scale-[0.98] transition-all duration-300 outline-none"
        >
          <ShoppingCart size={18} />
          ADD TO CART
        </button>
      </div>
    </div>
  );
};

export default ProductCard;
